├── README.md
├── informe.md
├── src/
│   ├── node.h
│   ├── edge.h
│   ├── union_find.h
│   ├── kruskal.h
│   ├── point_generator.h
│   └── main.cpp
├── Makefile
└── results/
    ├── resultados.csv
    └── plot.py
```

Let me start implementing. I'll use C++ with standard library.

First, let me design the structures:

```cpp
// Node structure
struct Node {
    double x, y;       // coordinates
    Node* parent;      // parent in union-find tree
    int size;          // size of the tree
};

// Edge structure
struct Edge {
    Node* u;
    Node* v;
    double weight;     // squared distance
};
```

For sorting and heap comparison:
```cpp
struct EdgeComparator {
    bool operator()(const Edge* a, const Edge* b) const {
        return a->weight < b->weight;
    }
};
```

For Union-Find:
```cpp
// Find without optimization - just walk up parents
Node* find_no_opt(Node* u) {
    while (u->parent != u) {
        u = u->parent;
    }
    return u;
}

// Find with path compression
Node* find_opt(Node* u) {
    if (u->parent == u) return u;
    u->parent = find_opt(u->parent);
    return u->parent;
}

// Union by size
void union_nodes(Node* root_u, Node* root_v) {
    if (root_u->size < root_v->size) {
        root_u->parent = root_v;
        root_v->size += root_u->size;
    } else {
        root_v->parent = root_u;
        root_u->size += root_v->size;
    }
}
```

For Kruskal:
```cpp
// With sorted array
double kruskal_sorted(Node* nodes, int n, Edge* edges, int m, bool use_opt) {
    // Sort edges by weight
    sort(edges, edges + m, EdgeComparator());

    // Initialize union-find
    for (int i = 0; i < n; i++) {
        nodes[i].parent = &nodes[i];
        nodes[i].size = 1;
    }

    int edges_added = 0;
    double total_weight = 0;
    for (int i = 0; i < m && edges_added < n - 1; i++) {
        Node* root_u = use_opt ? find_opt(edges[i].u) : find_no_opt(edges[i].u);
        Node* root_v = use_opt ? find_opt(edges[i].v) : find_no_opt(edges[i].v);
        if (root_u != root_v) {
            union_nodes(root_u, root_v);
            total_weight += edges[i].weight;
            edges_added++;
        }
    }
    return total_weight;
}

// With heap
double kruskal_heap(Node* nodes, int n, Edge* edges, int m, bool use_opt) {
    // Build heap
    priority_queue<Edge*, vector<Edge*>, EdgeComparator> heap(edges, edges + m);

    // Initialize union-find
    for (int i = 0; i < n; i++) {
        nodes[i].parent = &nodes[i];
        nodes[i].size = 1;
    }

    int edges_added = 0;
    double total_weight = 0;
    while (!heap.empty() && edges_added < n - 1) {
        Edge* e = heap.top();
        heap.pop();
        Node* root_u = use_opt ? find_opt(e->u) : find_no_opt(e->u);
        Node* root_v = use_opt ? find_opt(e->v) : find_no_opt(e->v);
        if (root_u != root_v) {
            union_nodes(root_u, root_v);
            total_weight += e->weight;
            edges_added++;
        }
    }
    return total_weight;
}
```

For the experiment:
- Generate 5 sequences of N points for each N in {2^5, ..., 2^12}
- For each sequence, compute all N(N-1)/2 edges
- For each of 4 variants, time the algorithm
- Save results to a CSV

