// node.h
// ---------------------------------------------------------------------------
// Estructura de datos que representa un nodo del grafo. Cada nodo
// corresponde a un punto en el plano bidimensional y, a la vez, es
// el elemento de un árbol dentro de la estructura Union-Find.
//
// Campos:
//   x, y    : coordenadas cartesianas del punto (double en [0,1]).
//   parent  : puntero al nodo padre en el árbol de Union-Find. Apunta
//             a sí mismo cuando el nodo es raíz de su árbol.
//   size    : cantidad de nodos que componen el árbol cuya raíz es este
//             nodo. Sólo tiene un valor válido cuando el nodo es raíz.
//
// Notas de implementación:
//   - Se usan punteros a Node (no índices) tal como pide el enunciado.
//   - El campo size sólo se mantiene consistente en la raíz.
// ---------------------------------------------------------------------------
#ifndef NODE_H
#define NODE_H

struct Node {
    double x;
    double y;
    Node* parent;
    int   size;
};

#endif // NODE_H

// edge.h
// ---------------------------------------------------------------------------
// Estructura de datos que representa una arista del grafo.
//
// Una arista conecta dos nodos (punteros a Node) y tiene asociado un
// peso, que para esta tarea es el cuadrado de la distancia euclidiana
// entre los dos puntos (es decir, d = (x1-x2)^2 + (y1-y2)^2).
//
// Campos:
//   u, v    : punteros a los nodos conectados por la arista.
//   weight  : peso de la arista (double, distancia euclidiana al cuadrado).
//
// El comparador EdgePtrLess permite ordenar punteros a Edge tanto
// con std::sort como con std::priority_queue (heap clásico).
// ---------------------------------------------------------------------------
#ifndef EDGE_H
#define EDGE_H

struct Node;       // forward declaration
struct Edge;       // forward declaration

struct Edge {
    Node*   u;
    Node*   v;
    double  weight;
};

// Comparador que ordena punteros a Edge por peso ascendente.
struct EdgePtrLess {
    bool operator()(const Edge* a, const Edge* b) const {
        return a->weight < b->weight;
    }
};

#endif // EDGE_H

// union_find.h
// ---------------------------------------------------------------------------
// Interfaz Union-Find (también llamada Disjoint Set Union) basada
// en punteros a Node, tal como pide el enunciado de la tarea.
//
// Se entregan dos versiones de find:
//   - find_no_opt : recorre la cadena de padres sin modificar nada.
//   - find_opt    : aplica path compression (optimización de find).
//
// La unión se hace siempre por tamaño: la raíz del árbol más pequeño
// pasa a ser hija de la raíz del árbol más grande, y se actualiza
// el contador size de la nueva raíz.
// ---------------------------------------------------------------------------
#ifndef UNION_FIND_H
#define UNION_FIND_H

#include "node.h"

// ---------------------------------------------------------------------------
// make_set
// Inicializa un nodo como un árbol independiente (raíz de sí mismo
// con tamaño 1). Se debe llamar para todos los nodos antes de usar
// find/union.
//   Parámetros:
//     x : nodo a inicializar. Se modifica in-place.
// ---------------------------------------------------------------------------
inline void make_set(Node* x) {
    x->parent = x;
    x->size   = 1;
}

// ---------------------------------------------------------------------------
// find_no_opt
// Versión SIN optimización. Recorre la cadena de padres hasta llegar
// a la raíz, sin modificar punteros. Equivale al find "ingenuo".
//   Parámetros:
//     x : nodo cualquiera (no necesariamente raíz).
//   Retorno:
//     Puntero a la raíz del árbol que contiene a x.
// ---------------------------------------------------------------------------
inline Node* find_no_opt(Node* x) {
    while (x->parent != x) {
        x = x->parent;
    }
    return x;
}

// ---------------------------------------------------------------------------
// find_opt
// Versión CON optimización (path compression). Cuando se busca la
// raíz de x, todos los nodos visitados en el camino quedan apuntando
// directamente a la raíz, aplanando el árbol para futuras consultas.
//   Parámetros:
//     x : nodo cualquiera (no necesariamente raíz).
//   Retorno:
//     Puntero a la raíz del árbol que contiene a x.
// ---------------------------------------------------------------------------
inline Node* find_opt(Node* x) {
    if (x->parent == x) return x;
    // Se aplica path compression de forma recursiva.
    x->parent = find_opt(x->parent);
    return x->parent;
}

// ---------------------------------------------------------------------------
// union_nodes
// Une dos árboles dados por sus raíces. Se aplica union-by-size:
// la raíz del árbol con menos nodos se cuelga como hija de la raíz
// del árbol con más nodos. Se asume que ru y rv son raíces
// distintas (la verificación se hace con find antes de llamar).
//   Parámetros:
//     ru : raíz del primer árbol.
//     rv : raíz del segundo árbol.
//   Retorno:
//     Puntero a la nueva raíz del árbol combinado.
// ---------------------------------------------------------------------------
inline Node* union_nodes(Node* ru, Node* rv) {
    if (ru == rv) return ru;
    if (ru->size < rv->size) {
        // ru tiene menos nodos: la colgamos de rv.
        ru->parent = rv;
        rv->size  += ru->size;
        return rv;
    } else {
        // rv tiene menos (o igual) nodos: la colgamos de ru.
        rv->parent = ru;
        ru->size  += rv->size;
        return ru;
    }
}

#endif // UNION_FIND_H

// kruskal.h
// ---------------------------------------------------------------------------
// Implementación de las 4 variantes del algoritmo de Kruskal para
// encontrar el árbol cobertor mínimo (MST) de un grafo completo no
// dirigido ponderado.
//
// Variantes implementadas:
//   1) kruskal_sorted_opt   : arreglo ordenado + find con path compression.
//   2) kruskal_heap_opt     : heap clásico        + find con path compression.
//   3) kruskal_sorted_no    : arreglo ordenado + find sin optimización.
//   4) kruskal_heap_no      : heap clásico        + find sin optimización.
//
// Las cuatro funciones reciben los nodos en un buffer contiguo y un
// arreglo de aristas (o punteros a aristas para el caso heap) y
// devuelven el peso total del MST encontrado. El tiempo de armado
// de la estructura de extracción (sort o construcción del heap) se
// cuenta como parte del algoritmo, tal como pide el enunciado.
// ---------------------------------------------------------------------------
#ifndef KRUSKAL_H
#define KRUSKAL_H

#include "node.h"
#include "edge.h"
#include "union_find.h"

#include <algorithm>
#include <vector>
#include <queue>

// ---------------------------------------------------------------------------
// kruskal_sorted_opt
//   Variante: arreglo ordenado + find con optimización.
//   Parámetros:
//     nodes   : arreglo de n nodos. Se inicializa in-place (cada nodo
//               pasa a ser una raíz independiente).
//     n       : cantidad de nodos.
//     edges   : arreglo de m aristas (por valor). Se ordena in-place.
//     m       : cantidad de aristas.
//   Retorno:
//     Peso total del MST (suma de pesos de las aristas del árbol).
// ---------------------------------------------------------------------------
inline double kruskal_sorted_opt(Node* nodes, int n,
                                 Edge* edges, int m) {
    // 1) Armar la estructura: ordenar las aristas por peso.
    std::sort(edges, edges + m, EdgePtrLess());

    // 2) Inicializar Union-Find.
    for (int i = 0; i < n; ++i) make_set(&nodes[i]);

    // 3) Recorrer aristas en orden creciente e ir agregando las que
    //    no formen ciclo.
    double total = 0.0;
    int    added = 0;
    for (int i = 0; i < m && added < n - 1; ++i) {
        Node* ru = find_opt(edges[i].u);
        Node* rv = find_opt(edges[i].v);
        if (ru != rv) {
            union_nodes(ru, rv);
            total += edges[i].weight;
            ++added;
        }
    }
    return total;
}

// ---------------------------------------------------------------------------
// kruskal_heap_opt
//   Variante: heap clásico + find con optimización.
//   Parámetros:
//     nodes   : arreglo de n nodos. Se inicializa in-place.
//     n       : cantidad de nodos.
//     edges   : arreglo de m aristas (por valor). No se modifica.
//     m       : cantidad de aristas.
//   Retorno:
//     Peso total del MST.
// ---------------------------------------------------------------------------
inline double kruskal_heap_opt(Node* nodes, int n,
                               Edge* edges, int m) {
    // 1) Armar la estructura: copiar punteros a un min-heap.
    //    Se cuenta como parte del tiempo de ejecución la construcción
    //    del heap, tal como pide el enunciado.
    std::vector<Edge*> ptrs;
    ptrs.reserve(m);
    for (int i = 0; i < m; ++i) ptrs.push_back(&edges[i]);
    std::priority_queue<Edge*, std::vector<Edge*>, EdgePtrLess> heap(
        EdgePtrLess(),
        std::move(ptrs)
    );

    // 2) Inicializar Union-Find.
    for (int i = 0; i < n; ++i) make_set(&nodes[i]);

    // 3) Extraer mínimos sucesivos hasta tener n-1 aristas.
    double total = 0.0;
    int    added = 0;
    while (!heap.empty() && added < n - 1) {
        Edge* e  = heap.top();
        heap.pop();
        Node* ru = find_opt(e->u);
        Node* rv = find_opt(e->v);
        if (ru != rv) {
            union_nodes(ru, rv);
            total += e->weight;
            ++added;
        }
    }
    return total;
}

// ---------------------------------------------------------------------------
// kruskal_sorted_no
//   Variante: arreglo ordenado + find sin optimización.
// ---------------------------------------------------------------------------
inline double kruskal_sorted_no(Node* nodes, int n,
                                Edge* edges, int m) {
    std::sort(edges, edges + m, EdgePtrLess());
    for (int i = 0; i < n; ++i) make_set(&nodes[i]);
    double total = 0.0;
    int    added = 0;
    for (int i = 0; i < m && added < n - 1; ++i) {
        Node* ru = find_no_opt(edges[i].u);
        Node* rv = find_no_opt(edges[i].v);
        if (ru != rv) {
            union_nodes(ru, rv);
            total += edges[i].weight;
            ++added;
        }
    }
    return total;
}

// ---------------------------------------------------------------------------
// kruskal_heap_no
//   Variante: heap clásico + find sin optimización.
// ---------------------------------------------------------------------------
inline double kruskal_heap_no(Node* nodes, int n,
                              Edge* edges, int m) {
    std::vector<Edge*> ptrs;
    ptrs.reserve(m);
    for (int i = 0; i < m; ++i) ptrs.push_back(&edges[i]);
    std::priority_queue<Edge*, std::vector<Edge*>, EdgePtrLess> heap(
        EdgePtrLess(),
        std::move(ptrs)
    );
    for (int i = 0; i < n; ++i) make_set(&nodes[i]);
    double total = 0.0;
    int    added = 0;
    while (!heap.empty() && added < n - 1) {
        Edge* e  = heap.top();
        heap.pop();
        Node* ru = find_no_opt(e->u);
        Node* rv = find_no_opt(e->v);
        if (ru != rv) {
            union_nodes(ru, rv);
            total += e->weight;
            ++added;
        }
    }
    return total;
}

#endif // KRUSKAL_H

// point_generator.h
// ---------------------------------------------------------------------------
// Utilidades para generar los puntos 2D y las aristas (con sus pesos)
// que se usan como entrada de los algoritmos.
//
//   - random_points(n, seed, out)  : genera n puntos en [0,1]^2
//                                     con el motor mt19937 sembrado
//                                     por 'seed' y los deja en 'out'.
//   - build_edges(nodes, n, edges) : genera las n*(n-1)/2 aristas
//                                     del grafo completo. Cada arista
//                                     guarda punteros a los dos nodos
//                                     y su peso, que es el cuadrado
//                                     de la distancia euclidiana.
// ---------------------------------------------------------------------------
#ifndef POINT_GENERATOR_H
#define POINT_GENERATOR_H

#include "node.h"
#include "edge.h"

#include <random>

// ---------------------------------------------------------------------------
// random_points
//   Genera n puntos (x, y) uniformes en el cuadrado unitario [0,1]^2.
//   Se usa std::mt19937_64 con semilla explícita para garantizar
//   reproducibilidad (misma semilla => mismos puntos).
//   Parámetros:
//     n    : cantidad de puntos a generar.
//     seed : semilla del motor de números aleatorios.
//     out  : arreglo de tamaño n donde se escriben los puntos. Se
//            inicializan parent=out+i y size=1 (estado válido para
//            Union-Find, aunque make_set los sobreescribirá después).
// ---------------------------------------------------------------------------
inline void random_points(int n, unsigned long long seed, Node* out) {
    std::mt19937_64 rng(seed);
    std::uniform_real_distribution<double> dist(0.0, 1.0);
    for (int i = 0; i < n; ++i) {
        out[i].x      = dist(rng);
        out[i].y      = dist(rng);
        out[i].parent = &out[i];
        out[i].size   = 1;
    }
}

// ---------------------------------------------------------------------------
// build_edges
//   Construye todas las aristas del grafo completo asociado a los
//   n nodos. Para cada par (i, j) con i < j, crea una arista con
//   punteros a nodes[i] y nodes[j] y peso = (xi-xj)^2 + (yi-yj)^2.
//   Parámetros:
//     nodes : arreglo de n nodos (sus coordenadas no se modifican).
//     n     : cantidad de nodos.
//     edges : arreglo de tamaño n*(n-1)/2 donde se escriben las
//             aristas generadas.
// ---------------------------------------------------------------------------
inline void build_edges(const Node* nodes, int n, Edge* edges) {
    int k = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            const double dx = nodes[i].x - nodes[j].x;
            const double dy = nodes[i].y - nodes[j].y;
            edges[k].u      = const_cast<Node*>(&nodes[i]);
            edges[k].v      = const_cast<Node*>(&nodes[j]);
            edges[k].weight = dx * dx + dy * dy;
            ++k;
        }
    }
}

#endif // POINT_GENERATOR_H

// main.cpp
// ---------------------------------------------------------------------------
// Programa principal de la Tarea 2.
//
// Para cada N en {2^5, 2^6, ..., 2^12} genera 5 secuencias de N
// puntos en [0,1]^2, calcula las N(N-1)/2 aristas con sus pesos y
// mide el tiempo de ejecución de las 4 variantes de Kruskal:
//   - Arreglo ordenado + find con optimización
//   - Heap             + find con optimización
//   - Arreglo ordenado + find sin optimización
//   - Heap             + find sin optimización
//
// Los tiempos se imprimen por pantalla en formato CSV y también se
// guardan en el archivo pasado como argumento (o results.csv por
// defecto). El reporte se procesa después con un script de Python
// para graficar.
// ---------------------------------------------------------------------------
#include "node.h"
#include "edge.h"
#include "union_find.h"
#include "kruskal.h"
#include "point_generator.h"

#include <chrono>
#include <cstdio>
#include <cstdlib>
#include <fstream>
#include <iostream>
#include <new>
#include <string>
#include <vector>

using clk = std::chrono::high_resolution_clock;

// ---------------------------------------------------------------------------
// time_one
//   Mide el tiempo de un callable que devuelve double (peso del MST).
//   Se mide con std::chrono::high_resolution_clock.
// ---------------------------------------------------------------------------
template <typename Fn>
static double time_one(Fn fn) {
    auto t0 = clk::now();
    double w = fn();
    auto t1 = clk::now();
    std::chrono::duration<double> d = t1 - t0;
    // Se imprime el peso en stderr para verificar correctitud, sin
    // contaminar el CSV de stdout.
    std::fprintf(stderr, "    MST weight = %.6f\n", w);
    return d.count();
}

// ---------------------------------------------------------------------------
// run_for_n
//   Para un N fijo, corre 5 secuencias con semillas distintas y mide
//   los 4 algoritmos sobre cada una. Devuelve un vector de 4 doubles
//   con los tiempos promedios (en segundos).
// ---------------------------------------------------------------------------
static void run_for_n(int n, double avg_out[4]) {
    const int trials = 5;
    double sum[4] = {0.0, 0.0, 0.0, 0.0};

    // Buffers para nodos y aristas. El grafo completo tiene m = n(n-1)/2
    // aristas. Se asignan con new para evitar stack overflow en N grandes.
    Node* nodes = new Node[n];
    const long long m_ll = 1LL * n * (n - 1) / 2;
    const int m = static_cast<int>(m_ll);
    Edge* edges = new Edge[m];

    for (int t = 0; t < trials; ++t) {
        const unsigned long long seed = 1000ULL * n + t;

        // 1) Generar puntos.
        random_points(n, seed, nodes);

        // 2) Construir aristas.
        build_edges(nodes, n, edges);

        std::cerr << "  [N=" << n << " trial=" << t
                  << " seed=" << seed << "]\n";

        // Para no contaminar las pruebas, se hace una copia del buffer
        // de aristas para cada variante que ordene in-place.
        // Las variantes con heap no modifican 'edges', así que pueden
        // compartir el buffer.
        Edge* edges_copy = new Edge[m];
        std::copy(edges, edges + m, edges_copy);

        // 3) Medir las 4 variantes.
        sum[0] += time_one([&] {
            return kruskal_sorted_opt(nodes, n, edges_copy, m);
        });
        // Después de kruskal_sorted_opt, edges_copy está ordenado y
        // los Union-Find están modificados. Se reinician las
        // estructuras y se restaura edges_copy para la siguiente
        // variante.
        std::copy(edges, edges + m, edges_copy);
        // Forzar reset del UF: se reinicializan los punteros parent
        // de los nodos. Como kruskal no libera memoria, basta con
        // llamar a make_set en cada nodo.
        for (int i = 0; i < n; ++i) {
            nodes[i].parent = &nodes[i];
            nodes[i].size   = 1;
        }

        sum[1] += time_one([&] {
            return kruskal_heap_opt(nodes, n, edges_copy, m);
        });
        for (int i = 0; i < n; ++i) {
            nodes[i].parent = &nodes[i];
            nodes[i].size   = 1;
        }

        sum[2] += time_one([&] {
            return kruskal_sorted_no(nodes, n, edges_copy, m);
        });
        std::copy(edges, edges + m, edges_copy);
        for (int i = 0; i < n; ++i) {
            nodes[i].parent = &nodes[i];
            nodes[i].size   = 1;
        }

        sum[3] += time_one([&] {
            return kruskal_heap_no(nodes, n, edges_copy, m);
        });

        delete[] edges_copy;
    }

    for (int k = 0; k < 4; ++k) avg_out[k] = sum[k] / trials;

    delete[] edges;
    delete[] nodes;
}

// ---------------------------------------------------------------------------
// main
//   Recorre N = 2^5 ... 2^12, llama a run_for_n y emite un CSV con
//   columnas: N, time_sorted_opt, time_heap_opt,
//            time_sorted_no,  time_heap_no.
// ---------------------------------------------------------------------------
int main(int argc, char** argv) {
    std::string out_path = "results.csv";
    if (argc >= 2) out_path = argv[1];

    std::ofstream ofs(out_path);
    if (!ofs) {
        std::cerr << "No se pudo abrir " << out_path << " para escritura.\n";
        return 1;
    }

    ofs << "N,time_sorted_opt,time_heap_opt,time_sorted_no,time_heap_no\n";
