// Comparador que ordena punteros a Edge por peso ascendente.
// Se usa con std::priority_queue<... EdgePtrMin> para implementar
// un min-heap (el de menor peso queda en el tope).
//
// NOTA: std::priority_queue es max-heap por defecto; el comparador
// define qué se considera "mayor". Para que el de menor peso quede
// en el tope, este comparador debe invertir el orden: retorna
// true si a tiene peso ESTRICTAMENTE MAYOR que b. Así, la priority
// queue considera que b es "mayor" que a, y por lo tanto b (el de
// menor peso) queda en el tope.
struct EdgePtrMin {
    bool operator()(const Edge* a, const Edge* b) const {
        return a->weight > b->weight;
    }
};

